app.get('/events', (req, res) => {
	const sse = res.sse({
		retry: 5000,
		autoId: true,
		keepAlive: 30000
	})

	sse.send('connected')

	const iv = setInterval(() => {
		sse.event('tick', { time: Date.now() })
	}, 1000)

	sse.on('close', () => {
		clearInterval(iv)
		console.log('client disconnected')
	})
})

