const { createApp, compress, json } = require('zero-http')
const app = createApp()

// brotli > gzip > deflate, auto-negotiated
app.use(compress({ threshold: 512, level: 6 }))
app.use(json())

app.get('/big', (req, res) => {
	// This response is large enough to be compressed
	res.json({ data: 'x'.repeat(10000) })
})

app.get('/small', (req, res) => {
	// Below threshold — sent uncompressed
	res.json({ ok: true })
})

app.listen(3000)

